SELECT COUNT(*) AS count FROM (SELECT * FROM "PATENTS"."PATENTS"."PUBLICATIONS" WHERE "country_code" = 'CN' AND "grant_date" >= 20100101 AND "grant_date" <= 20231231) AS granted_patents INNER JOIN (SELECT "family_id" FROM "PATENTS"."PATENTS"."PUBLICATIONS" WHERE "application_number" IS NOT NULL GROUP BY "family_id" HAVING COUNT(DISTINCT "application_number") > 1) AS fam_counts ON granted_patents."family_id" = fam_counts."family_id"